import React from 'react';
import { LinPageLayout, type LinPageHeaderProps } from '@linm-soft/common-components';
import {
  CatalogListMasterListFooter,
  useCatalogListMasterToolbarBundle,
  type CatalogListMasterRow,
  type CatalogListMasterToolbarSectionProps,
} from './CatalogListMasterPageChrome';
import styles from '../../styles/erpPage.module.css';

export type CatalogListMasterLinPageLayoutProps<T extends CatalogListMasterRow> =
  CatalogListMasterToolbarSectionProps<T> & {
    pageId?: string;
    header: LinPageHeaderProps;
    listTitle: string;
    /**
     * Help dưới tiêu đề «Danh sách …» (menu dòng) — SSOT `getErpListRowMenuHelp`.
     * Bật khi grid có `onRowOpenActionMenu` (GAP-P2-94).
     */
    listRowMenuHelp?: boolean;
    filters?: React.ReactNode;
    filtersTestId?: string;
    filterMaxWidthPx?: number | null;
    showTableLoading: boolean;
    /** Đổi trang server-paged — busy overlay, không skeleton. */
    pageLoading?: boolean;
    skeletonRows?: number;
    children: React.ReactNode;
    page: number;
    pageSize: number;
    onPageChange: (page: number) => void;
    onPageSizeChange: (size: number) => void;
    schemaEditorModal?: React.ReactNode;
    extraModals?: React.ReactNode;
    /** Content above LinPageLayout (e.g. outer tab bar before header). */
    topChrome?: React.ReactNode;
    /** Between page header and selection banner (e.g. tab bar before toolbar). */
    beforeToolbarExtra?: React.ReactNode;
    /** Between toolbar and list card (e.g. tab bar after toolbar). */
    afterToolbar?: React.ReactNode;
    className?: string;
    useCatalogToolbarPreset?: boolean;
  };

/** Full catalog list shell — `LinPageLayout` + flex root (GAP-P2-LAYOUT-06). */
export function CatalogListMasterLinPageLayout<T extends CatalogListMasterRow>({
  testIdPrefix,
  pageId,
  header,
  listTitle,
  listRowMenuHelp,
  filters,
  filtersTestId,
  filterMaxWidthPx = 1000,
  showTableLoading,
  pageLoading,
  skeletonRows,
  children,
  page,
  pageSize,
  onPageChange,
  onPageSizeChange,
  schemaEditorModal,
  extraModals,
  topChrome,
  beforeToolbarExtra,
  afterToolbar,
  className,
  useCatalogToolbarPreset,
  totalCount,
  catalogKind,
  shared,
  ...toolbarRest
}: CatalogListMasterLinPageLayoutProps<T>): React.ReactElement {
  const toolbarProps = {
    testIdPrefix,
    catalogKind,
    shared,
    totalCount,
    ...toolbarRest,
  };
  const bundle = useCatalogListMasterToolbarBundle(toolbarProps);
  const usePreset = (useCatalogToolbarPreset ?? !bundle.hasSharedToolbar) && !afterToolbar;

  return (
    <div
      className={[styles.catalogListRoot, className].filter(Boolean).join(' ')}
      data-catalog-list-page
      data-testid={`${testIdPrefix}-list`}
    >
      {topChrome}
      <LinPageLayout
        kind="catalog"
        testIdPrefix={testIdPrefix}
        pageId={pageId}
        pageClassName={styles.catalogListPage}
        header={header}
        toolbar={usePreset ? undefined : (
          <>
            {bundle.toolbar}
            {afterToolbar}
          </>
        )}
        catalogToolbar={usePreset ? bundle.catalogToolbarPreset : undefined}
        beforeToolbar={(
          <>
            {beforeToolbarExtra}
            {bundle.beforeToolbar}
          </>
        )}
        listTitle={listTitle}
        listRowMenuHelp={listRowMenuHelp}
        filters={filters}
        filterMaxWidthPx={filterMaxWidthPx}
        filtersTestId={filtersTestId}
        showTableLoading={showTableLoading}
        pageLoading={pageLoading}
        skeletonRows={skeletonRows}
        footer={(
          <CatalogListMasterListFooter
            testIdPrefix={testIdPrefix}
            catalogKind={catalogKind}
            shared={shared}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={onPageChange}
            onPageSizeChange={onPageSizeChange}
          />
        )}
        modals={(
          <>
            {bundle.modals}
            {schemaEditorModal}
            {extraModals}
          </>
        )}
      >
        {children}
      </LinPageLayout>
    </div>
  );
}
